1365 static DenormalMode getInstrDenormalMode(const Instruction *CtxI, Type *Ty) {
1366   if (!CtxI || !CtxI->getParent() || !CtxI->getFunction())
1367     return DenormalMode::getDynamic();
1368   return CtxI->getFunction()->getDenormalMode(Ty->getFltSemantics());
