1371 static ConstantFP *flushDenormalConstantFP(ConstantFP *CFP,
1372                                            const Instruction *Inst,
1373                                            bool IsOutput,
1374                                            bool AllowNonDeterministic) {
1375   const APFloat &APF = CFP->getValueAPF();
1376   if (!APF.isDenormal())
1377     return CFP;
1378 
1379   DenormalMode Mode = getInstrDenormalMode(Inst, CFP->getType());
1380   return flushDenormalConstant(CFP->getType(), APF,
1381                                IsOutput ? Mode.Output : Mode.Input,
1382                                AllowNonDeterministic);
1383 }
