1385 Constant *llvm::FlushFPConstant(Constant *Operand, const Instruction *Inst,
1386                                 bool IsOutput, bool AllowNonDeterministic) {
1387   if (ConstantFP *CFP = dyn_cast<ConstantFP>(Operand))
1388     return flushDenormalConstantFP(CFP, Inst, IsOutput, AllowNonDeterministic);
1389 
1390   if (isa<ConstantAggregateZero, UndefValue>(Operand))
1391     return Operand;
1392 
1393   Type *Ty = Operand->getType();
1394   VectorType *VecTy = dyn_cast<VectorType>(Ty);
1395   if (VecTy) {
1396     if (auto *Splat = dyn_cast_or_null<ConstantFP>(Operand->getSplatValue())) {
1397       ConstantFP *Folded =
1398           flushDenormalConstantFP(Splat, Inst, IsOutput, AllowNonDeterministic);
1399       if (!Folded)
1400         return nullptr;
1401       return ConstantVector::getSplat(VecTy->getElementCount(), Folded);
1402     }
1403 
1404     Ty = VecTy->getElementType();
1405   }
1406 
1407   if (isa<ConstantExpr>(Operand))
1408     return Operand;
1409 
1410   if (const auto *CV = dyn_cast<ConstantVector>(Operand)) {
1411     SmallVector<Constant *, 16> NewElts;
1412     for (unsigned i = 0, e = CV->getNumOperands(); i != e; ++i) {
1413       Constant *Element = CV->getAggregateElement(i);
1414       if (isa<UndefValue>(Element)) {
1415         NewElts.push_back(Element);
1416         continue;
1417       }
1418 
1419       ConstantFP *CFP = dyn_cast<ConstantFP>(Element);
1420       if (!CFP)
1421         return nullptr;
1422 
1423       ConstantFP *Folded =
1424           flushDenormalConstantFP(CFP, Inst, IsOutput, AllowNonDeterministic);
1425       if (!Folded)
1426         return nullptr;
1427       NewElts.push_back(Folded);
1428     }
1429 
1430     return ConstantVector::get(NewElts);
1431   }
1432 
1433   if (const auto *CDV = dyn_cast<ConstantDataVector>(Operand)) {
1434     SmallVector<Constant *, 16> NewElts;
1435     for (unsigned I = 0, E = CDV->getNumElements(); I < E; ++I) {
1436       const APFloat &Elt = CDV->getElementAsAPFloat(I);
1437       if (!Elt.isDenormal()) {
1438         NewElts.push_back(ConstantFP::get(Ty, Elt));
1439       } else {
1440         DenormalMode Mode = getInstrDenormalMode(Inst, Ty);
1441         ConstantFP *Folded =
1442             flushDenormalConstant(Ty, Elt, IsOutput ? Mode.Output : Mode.Input,
1443                                   AllowNonDeterministic);
1444         if (!Folded)
1445           return nullptr;
1446         NewElts.push_back(Folded);
1447       }
1448     }
1449 
1450     return ConstantVector::get(NewElts);
1451   }
1452 
1453   return nullptr;
1454 }
