1456 Constant *llvm::ConstantFoldFPInstOperands(unsigned Opcode, Constant *LHS,
1457                                            Constant *RHS, const DataLayout &DL,
1458                                            const Instruction *I,
1459                                            bool AllowNonDeterministic) {
1460   if (Instruction::isBinaryOp(Opcode)) {
1461     // Flush denormal inputs if needed.
1462     Constant *Op0 =
1463         FlushFPConstant(LHS, I, /*IsOutput=*/false, AllowNonDeterministic);
1464     if (!Op0)
1465       return nullptr;
1466     Constant *Op1 =
1467         FlushFPConstant(RHS, I, /*IsOutput=*/false, AllowNonDeterministic);
1468     if (!Op1)
1469       return nullptr;
1470 
1471     // If nsz or an algebraic FMF flag is set, the result of the FP operation
1472     // may change due to future optimization. Don't constant fold them if
1473     // non-deterministic results are not allowed.
1474     if (!AllowNonDeterministic)
1475       if (auto *FP = dyn_cast_or_null<FPMathOperator>(I))
1476         if (FP->hasNoSignedZeros() || FP->hasAllowReassoc() ||
1477             FP->hasAllowContract() || FP->hasAllowReciprocal())
1478           return nullptr;
1479 
1480     // Calculate constant result.
1481     Constant *C = ConstantFoldBinaryOpOperands(Opcode, Op0, Op1, DL);
1482     if (!C)
1483       return nullptr;
1484 
1485     // Flush denormal output if needed.
1486     C = FlushFPConstant(C, I, /*IsOutput=*/true, AllowNonDeterministic);
1487     if (!C)
1488       return nullptr;
1489 
1490     // The precise NaN value is non-deterministic.
1491     if (!AllowNonDeterministic && C->isNaN())
1492       return nullptr;
1493 
1494     return C;
1495   }
1496   // If instruction lacks a parent/function and the denormal mode cannot be
1497   // determined, use the default (IEEE).
1498   return ConstantFoldBinaryOpOperands(Opcode, LHS, RHS, DL);
1499 }
