1501 Constant *llvm::ConstantFoldCastOperand(unsigned Opcode, Constant *C,
1502                                         Type *DestTy, const DataLayout &DL) {
1503   assert(Instruction::isCast(Opcode));
1504 
1505   if (auto *CE = dyn_cast<ConstantExpr>(C))
1506     if (CE->isCast())
1507       if (unsigned NewOp = CastInst::isEliminableCastPair(
1508               Instruction::CastOps(CE->getOpcode()),
1509               Instruction::CastOps(Opcode), CE->getOperand(0)->getType(),
1510               C->getType(), DestTy, &DL))
1511         return ConstantFoldCastOperand(NewOp, CE->getOperand(0), DestTy, DL);
1512 
1513   switch (Opcode) {
1514   default:
1515     llvm_unreachable("Missing case");
1516   case Instruction::PtrToAddr:
1517   case Instruction::PtrToInt:
1518     if (auto *CE = dyn_cast<ConstantExpr>(C)) {
1519       Constant *FoldedValue = nullptr;
1520       // If the input is an inttoptr, eliminate the pair.  This requires knowing
1521       // the width of a pointer, so it can't be done in ConstantExpr::getCast.
1522       if (CE->getOpcode() == Instruction::IntToPtr) {
1523         // zext/trunc the inttoptr to pointer/address size.
1524         Type *MidTy = Opcode == Instruction::PtrToInt
1525                           ? DL.getAddressType(CE->getType())
1526                           : DL.getIntPtrType(CE->getType());
1527         FoldedValue = ConstantFoldIntegerCast(CE->getOperand(0), MidTy,
1528                                               /*IsSigned=*/false, DL);
1529       } else if (auto *GEP = dyn_cast<GEPOperator>(CE)) {
1530         // If we have GEP, we can perform the following folds:
1531         // (ptrtoint/ptrtoaddr (gep null, x)) -> x
1532         // (ptrtoint/ptrtoaddr (gep (gep null, x), y) -> x + y, etc.
1533         unsigned BitWidth = DL.getIndexTypeSizeInBits(GEP->getType());
1534         APInt BaseOffset(BitWidth, 0);
1535         auto *Base = cast<Constant>(GEP->stripAndAccumulateConstantOffsets(
1536             DL, BaseOffset, /*AllowNonInbounds=*/true));
1537         if (Base->isNullValue()) {
1538           FoldedValue = ConstantInt::get(CE->getContext(), BaseOffset);
1539         } else {
1540           // ptrtoint/ptrtoaddr (gep i8, Ptr, (sub 0, V))
1541           //   -> sub (ptrtoint/ptrtoaddr Ptr), V
1542           if (GEP->getNumIndices() == 1 &&
1543               GEP->getSourceElementType()->isIntegerTy(8)) {
1544             auto *Ptr = cast<Constant>(GEP->getPointerOperand());
1545             auto *Sub = dyn_cast<ConstantExpr>(GEP->getOperand(1));
1546             Type *IntIdxTy = DL.getIndexType(Ptr->getType());
1547             if (Sub && Sub->getType() == IntIdxTy &&
1548                 Sub->getOpcode() == Instruction::Sub &&
1549                 Sub->getOperand(0)->isNullValue())
1550               FoldedValue = ConstantExpr::getSub(
1551                   ConstantExpr::getCast(Opcode, Ptr, IntIdxTy),
1552                   Sub->getOperand(1));
1553           }
1554         }
1555       }
1556       if (FoldedValue) {
1557         // Do a zext or trunc to get to the ptrtoint/ptrtoaddr dest size.
1558         return ConstantFoldIntegerCast(FoldedValue, DestTy, /*IsSigned=*/false,
1559                                        DL);
1560       }
1561     }
1562     break;
1563   case Instruction::IntToPtr:
1564     // If the input is a ptrtoint, turn the pair into a ptr to ptr bitcast if
1565     // the int size is >= the ptr size and the address spaces are the same.
1566     // This requires knowing the width of a pointer, so it can't be done in
1567     // ConstantExpr::getCast.
1568     if (auto *CE = dyn_cast<ConstantExpr>(C)) {
1569       if (CE->getOpcode() == Instruction::PtrToInt) {
1570         Constant *SrcPtr = CE->getOperand(0);
1571         unsigned SrcPtrSize = DL.getPointerTypeSizeInBits(SrcPtr->getType());
1572         unsigned MidIntSize = CE->getType()->getScalarSizeInBits();
1573 
1574         if (MidIntSize >= SrcPtrSize) {
1575           unsigned SrcAS = SrcPtr->getType()->getPointerAddressSpace();
1576           if (SrcAS == DestTy->getPointerAddressSpace())
1577             return FoldBitCast(CE->getOperand(0), DestTy, DL);
1578         }
1579       }
1580     }
1581     break;
1582   case Instruction::Trunc:
1583   case Instruction::ZExt:
1584   case Instruction::SExt:
1585   case Instruction::FPTrunc:
1586   case Instruction::FPExt:
1587   case Instruction::UIToFP:
1588   case Instruction::SIToFP:
1589   case Instruction::FPToUI:
1590   case Instruction::FPToSI:
1591   case Instruction::AddrSpaceCast:
1592     break;
1593   case Instruction::BitCast:
1594     return FoldBitCast(C, DestTy, DL);
1595   }
1596 
1597   if (ConstantExpr::isDesirableCastOp(Opcode))
1598     return ConstantExpr::getCast(Opcode, C, DestTy);
1599   return ConstantFoldCastInstruction(Opcode, C, DestTy);
1600 }
