1602 Constant *llvm::ConstantFoldIntegerCast(Constant *C, Type *DestTy,
1603                                         bool IsSigned, const DataLayout &DL) {
1604   Type *SrcTy = C->getType();
1605   if (SrcTy == DestTy)
1606     return C;
1607   if (SrcTy->getScalarSizeInBits() > DestTy->getScalarSizeInBits())
1608     return ConstantFoldCastOperand(Instruction::Trunc, C, DestTy, DL);
1609   if (IsSigned)
1610     return ConstantFoldCastOperand(Instruction::SExt, C, DestTy, DL);
1611   return ConstantFoldCastOperand(Instruction::ZExt, C, DestTy, DL);
1612 }
