1136 Constant *llvm::ConstantFoldInstruction(const Instruction *I,
1137                                         const DataLayout &DL,
1138                                         const TargetLibraryInfo *TLI) {
1139   // Handle PHI nodes quickly here...
1140   if (auto *PN = dyn_cast<PHINode>(I)) {
